// src/shell/store/tabs.ts

import { v4 as uuid } from "uuid";
import type { TabState, StatusBarData, CompactEvent } from "../../shared/types.js";
import type { Message } from "../../shared/types.js";

export interface TabsSlice {
  tabs: TabState[];
  activeTabId: string | null;
  tabMessages: Record<string, Message[]>;
  tabStreamBuffer: Record<string, string>;
  tabStatus: Record<string, StatusBarData>;
  tabCompactEvents: Record<string, CompactEvent[]>;

  createTab: (name?: string) => TabState;
  closeTab: (tabId: string) => void;
  setActiveTab: (tabId: string) => void;
  setWorkerReady: (tabId: string, workerId: string) => void;
  appendMessage: (tabId: string, msg: Message) => void;
  setStreamBuffer: (tabId: string, content: string) => void;
  appendStreamBuffer: (tabId: string, chunk: string) => void;
  clearStreamBuffer: (tabId: string) => void;
  updateTabStatus: (tabId: string, data: Partial<StatusBarData>) => void;
  addCompactEvent: (tabId: string, event: CompactEvent) => void;
  renameTab: (tabId: string, name: string) => void;
}

export function createTabsSlice(
  set: (fn: (state: any) => any) => void,
  get: () => any
): TabsSlice {
  return {
    tabs: [],
    activeTabId: null,
    tabMessages: {},
    tabStreamBuffer: {},
    tabStatus: {},
    tabCompactEvents: {},

    createTab: (name?: string) => {
      const state = get();
      const index = state.tabs.length + 1;
      const tab: TabState = {
        id: uuid(),
        index,
        sessionId: uuid(),
        name: name || `Session ${index}`,
        workerId: null,
        workerReady: false,
        worktreePath: null,
        worktreeBranch: null,
      };

      set((s: any) => ({
        tabs: [...s.tabs, tab],
        activeTabId: tab.id,
        tabMessages: { ...s.tabMessages, [tab.id]: [] },
        tabStreamBuffer: { ...s.tabStreamBuffer, [tab.id]: "" },
        tabStatus: { ...s.tabStatus, [tab.id]: createEmptyStatus() },
        tabCompactEvents: { ...s.tabCompactEvents, [tab.id]: [] },
      }));

      return tab;
    },

    closeTab: (tabId: string) => {
      set((s: any) => {
        const remaining = s.tabs.filter((t: TabState) => t.id !== tabId);
        const { [tabId]: _m, ...restMessages } = s.tabMessages;
        const { [tabId]: _s, ...restStream } = s.tabStreamBuffer;
        const { [tabId]: _st, ...restStatus } = s.tabStatus;
        const { [tabId]: _c, ...restCompact } = s.tabCompactEvents;

        return {
          tabs: remaining,
          activeTabId:
            s.activeTabId === tabId
              ? remaining[remaining.length - 1]?.id ?? null
              : s.activeTabId,
          tabMessages: restMessages,
          tabStreamBuffer: restStream,
          tabStatus: restStatus,
          tabCompactEvents: restCompact,
        };
      });
    },

    setActiveTab: (tabId: string) => set(() => ({ activeTabId: tabId })),

    setWorkerReady: (tabId: string, workerId: string) => {
      set((s: any) => ({
        tabs: s.tabs.map((t: TabState) =>
          t.id === tabId ? { ...t, workerId, workerReady: true } : t
        ),
      }));
    },

    appendMessage: (tabId: string, msg: Message) => {
      set((s: any) => ({
        tabMessages: {
          ...s.tabMessages,
          [tabId]: [...(s.tabMessages[tabId] || []), msg],
        },
      }));
    },

    setStreamBuffer: (tabId: string, content: string) => {
      set((s: any) => ({
        tabStreamBuffer: { ...s.tabStreamBuffer, [tabId]: content },
      }));
    },

    appendStreamBuffer: (tabId: string, chunk: string) => {
      set((s: any) => ({
        tabStreamBuffer: {
          ...s.tabStreamBuffer,
          [tabId]: (s.tabStreamBuffer[tabId] || "") + chunk,
        },
      }));
    },

    clearStreamBuffer: (tabId: string) => {
      set((s: any) => ({
        tabStreamBuffer: { ...s.tabStreamBuffer, [tabId]: "" },
      }));
    },

    updateTabStatus: (tabId: string, data: Partial<StatusBarData>) => {
      set((s: any) => ({
        tabStatus: {
          ...s.tabStatus,
          [tabId]: { ...(s.tabStatus[tabId] || createEmptyStatus()), ...data },
        },
      }));
    },

    addCompactEvent: (tabId: string, event: CompactEvent) => {
      set((s: any) => ({
        tabCompactEvents: {
          ...s.tabCompactEvents,
          [tabId]: [...(s.tabCompactEvents[tabId] || []), event],
        },
      }));
    },

    renameTab: (tabId: string, name: string) => {
      set((s: any) => ({
        tabs: s.tabs.map((t: TabState) =>
          t.id === tabId ? { ...t, name } : t
        ),
      }));
    },
  };
}

function createEmptyStatus(): StatusBarData {
  return {
    model: null,
    totalTokens: 0,
    contextTokens: 0,
    contextMaxTokens: 1000000,
    contextPercent: 0,
    style: null,
    sessionId: null,
    durationSeconds: 0,
    cost: 0,
    gitBranch: null,
    gitDiffStats: null,
    compactedAt: null,
  };
}
```

