```typescript
// src/shell/hooks/useWorkerManager.ts

import { useEffect, useRef, useCallback } from "react";
import { fork, type ChildProcess } from "node:child_process";
import fs from "node:fs";
import net from "node:net";
import { v4 as uuid } from "uuid";
import { useStore } from "../store/index.js";
import {
  createIPCServer,
  sendMessage,
  socketPath,
  type IPCMessage,
  type WorkerToShellMessage,
  type ShellToWorkerMessage,
} from "../../shared/ipc.js";
import { config, ensureDirs } from "../../shared/config.js";
import type { Pin } from "../../shared/types.js";

interface WorkerHandle {
  process: ChildProcess;
  socket: net.Socket | null;
  server: net.Server;
  workerId: string;
  tabId: string;
}

export function useWorkerManager(cwd: string) {
  const workersRef = useRef<Map<string, WorkerHandle>>(new Map());

  const spawnWorker = useCallback(
    (tabId: string): string => {
      ensureDirs();
      const workerId = uuid();
      const sockPath = socketPath(workerId);

      // Clean up stale socket
      try {
        fs.unlinkSync(sockPath);
      } catch {}

      // Create IPC server for this worker
      const server = createIPCServer(sockPath, (msg, socket) => {
        const handle = workersRef.current.get(tabId);
        if (handle && !handle.socket) {
          handle.socket = socket;
        }
        handleWorkerMessage(tabId, msg as WorkerToShellMessage);
      });

      // Fork worker process
      const workerProcess = fork(config.workerEntry, [workerId, cwd], {
        stdio: "pipe",
        env: { ...process.env },
      });

      workerProcess.on("exit", (code) => {
        cleanupWorker(tabId);
        if (code !== 0) {
          useStore.getState().appendMessage(tabId, {
            id: uuid(),
            sessionId: tabId,
            role: "system",
            content: `Worker exited with code ${code}`,
            tokens: 0,
            cost: 0,
            createdAt: Date.now(),
          });
        }
      });

      workersRef.current.set(tabId, {
        process: workerProcess,
        socket: null,
        server,
        workerId,
        tabId,
      });

      return workerId;
    },
    [cwd]
  );

  function handleWorkerMessage(tabId: string, msg: WorkerToShellMessage): void {
    const store = useStore.getState();

    switch (msg.type) {
      case "ready":
        store.setWorkerReady(tabId, msg.workerId);
        break;

      case "stream_chunk":
        store.appendStreamBuffer(tabId, msg.content);
        break;

      case "message_complete":
        store.clearStreamBuffer(tabId);
        store.appendMessage(tabId, {
          id: uuid(),
          sessionId: tabId,
          role: msg.role as any,
          content: msg.content,
          tokens: msg.tokens,
          cost: msg.cost,
          createdAt: Date.now(),
        });
        break;

      case "status_update":
        store.updateTabStatus(tabId, msg.data);
        break;

      case "context_compacted":
        store.addCompactEvent(tabId, msg.event);
        break;

      case "error":
        store.appendMessage(tabId, {
          id: uuid(),
          sessionId: tabId,
          role: "system",
          content: `Error: ${msg.message}`,
          tokens: 0,
          cost: 0,
          createdAt: Date.now(),
        });
        break;
    }
  }

  function sendToWorker(tabId: string, msg: ShellToWorkerMessage): void {
    const handle = workersRef.current.get(tabId);
    if (handle?.socket) {
      sendMessage(handle.socket, msg);
    }
  }

  function killWorker(tabId: string): void {
    const handle = workersRef.current.get(tabId);
    if (handle) {
      sendToWorker(tabId, { type: "shutdown" });
      setTimeout(() => {
        handle.process.kill("SIGTERM");
        cleanupWorker(tabId);
      }, 2000);
    }
  }

  function cleanupWorker(tabId: string): void {
    const handle = workersRef.current.get(tabId);
    if (handle) {
      handle.socket?.destroy();
      handle.server.close();
      try {
        fs.unlinkSync(socketPath(handle.workerId));
      } catch {}
      workersRef.current.delete(tabId);
    }
  }

  // Cleanup all workers on unmount
  useEffect(() => {
    return () => {
      for (const [tabId] of workersRef.current) {
        killWorker(tabId);
      }
    };
  }, []);

  return {
    spawnWorker,
    sendToWorker,
    killWorker,
    sendPrompt: (tabId: string, prompt: string, pins: Pin[]) => {
      const store = useStore.getState();
      // Add user message to store
      store.appendMessage(tabId, {
        id: uuid(),
        sessionId: tabId,
        role: "user",
        content: prompt,
        tokens: 0,
        cost: 0,
        createdAt: Date.now(),
      });
      // Send to worker
      sendToWorker(tabId, { type: "send_prompt", prompt, pins });
    },
  };
}
