// src/shell/store/sessions.ts

import type { Session } from "../../shared/types.js";

export interface SessionsSlice {
  sessions: Session[];
  sessionFilter: string;
  setSessions: (sessions: Session[]) => void;
  setSessionFilter: (filter: string) => void;
  updateSessionColor: (sessionId: string, color: string) => void;
  updateSessionName: (sessionId: string, name: string) => void;
  filteredSessions: () => Session[];
}

export function createSessionsSlice(
  set: (fn: (state: any) => any) => void,
  get: () => any
): SessionsSlice {
  return {
    sessions: [],
    sessionFilter: "",

    setSessions: (sessions: Session[]) => set(() => ({ sessions })),

    setSessionFilter: (filter: string) => set(() => ({ sessionFilter: filter })),

    updateSessionColor: (sessionId: string, color: string) => {
      set((s: any) => ({
        sessions: s.sessions.map((session: Session) =>
          session.id === sessionId ? { ...session, color } : session
        ),
      }));
    },

    updateSessionName: (sessionId: string, name: string) => {
      set((s: any) => ({
        sessions: s.sessions.map((session: Session) =>
          session.id === sessionId ? { ...session, name } : session
        ),
      }));
    },

    filteredSessions: () => {
      const state = get();
      const filter = state.sessionFilter.toLowerCase();
      if (!filter) return state.sessions;
      return state.sessions.filter((s: Session) =>
        s.name.toLowerCase().includes(filter)
      );
    },
  };
}
