```typescript
// src/shell/hooks/useGit.ts

import { useEffect, useRef } from "react";
import { useStore } from "../store/index.js";
import simpleGit from "simple-git";

export function useGit(cwd: string): void {
  const activeTabId = useStore((s) => s.activeTabId);
  const tabs = useStore((s) => s.tabs);
  const updateTabStatus = useStore((s) => s.updateTabStatus);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    async function updateGitInfo(): Promise<void> {
      if (!activeTabId) return;

      const activeTab = tabs.find((t) => t.id === activeTabId);
      const gitCwd = activeTab?.worktreePath || cwd;

      try {
        const git = simpleGit(gitCwd);
        const status = await git.status();
        const diff = await git.diffSummary();

        updateTabStatus(activeTabId, {
          gitBranch: status.current,
          gitDiffStats: {
            added: diff.insertions,
            removed: diff.deletions,
            modified: diff.files.length,
          },
        });
      } catch {
        updateTabStatus(activeTabId, {
          gitBranch: null,
          gitDiffStats: null,
        });
      }
    }

    updateGitInfo();

    // Poll every 5 seconds
    intervalRef.current = setInterval(updateGitInfo, 5000);

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [activeTabId, cwd, tabs, updateTabStatus]);
}
```

